dark.customCSS:
/* --- AETHER: ATMOSPHERIC TRANSLUCENCY --- */

@keyframes holographic-shimmer {
	0% { border-image-source: conic-gradient(from 0deg, transparent, rgba(128, 163, 255, 0.3), transparent); }
	100% { border-image-source: conic-gradient(from 360deg, transparent, rgba(128, 163, 255, 0.3), transparent); }
}

/* The Refractive Layer */
#sidebar, .prose, .bg-gray-850, input, textarea {
	background: rgba(7, 12, 26, 0.4) !important;
	backdrop-filter: blur(40px) saturate(1.8) contrast(1.1) !important;
	-webkit-backdrop-filter: blur(40px) saturate(1.8) contrast(1.1) !important;
	border: 1px solid transparent !important;
	border-image: conic-gradient(from 0deg, transparent, rgba(128, 163, 255, 0.2), transparent) 1 !important;
	animation: holographic-shimmer 8s linear infinite;
	border-radius: 24px !important;
}

/* Nebula Typography */
.prose h1, .prose h2, .prose h3 {
	color: #ffffff !important;
	font-weight: 200 !important;
	letter-spacing: -0.01em;
	text-shadow: 
		0 0 10px rgba(84, 132, 255, 0.5),
		0 0 20px rgba(173, 194, 255, 0.3) !important;
}

/* The Liquid Scrollbar */
::-webkit-scrollbar {
	width: 4px;
}
::-webkit-scrollbar-thumb {
	background: linear-gradient(transparent, rgba(255,255,255,0.3), transparent) !important;
	border-radius: 10px;
}

/* High-Fidelity Buttons */
button.bg-blue-500, button.bg-blue-600, .bg-black {
	background: rgba(255, 255, 255, 0.05) !important;
	backdrop-filter: blur(10px);
	border: 1px solid rgba(255, 255, 255, 0.1) !important;
	color: #fff !important;
	border-radius: 30px !important;
	transition: all 0.5s cubic-bezier(0.23, 1, 0.32, 1);
}

button.bg-blue-500:hover {
	background: rgba(255, 255, 255, 1) !important;
	color: #040710 !important;
	box-shadow: 0 0 30px rgba(255, 255, 255, 0.4);
}

/* Clean Chat List */
.chat-item {
	transition: background 0.3s ease;
	border-radius: 12px !important;
}
.chat-item:hover {
	background: rgba(255, 255, 255, 0.03) !important;
}

dark.canvasScript:
/**
 * Title: Gaseous Nebula Flow
 * Description: Billowing cosmic gas clouds that react to the mouse like gravitational fluid.
 */

const CONFIG = {
    cloudCount: 6,
    baseColors: [
        'rgba(30, 50, 150, 0.12)',
        'rgba(80, 40, 120, 0.1)',
        'rgba(20, 100, 140, 0.08)',
        'rgba(10, 20, 60, 0.15)'
    ],
    mouseGravity: 0.02
};

let canvas, ctx, w, h;
let clouds = [];
let mouse = { x: -5000, y: -5000 };

self.onmessage = (e) => {
    if (e.data.type === 'init') {
        canvas = e.data.canvas; ctx = canvas.getContext('2d');
        resize(e.data.width, e.data.height);
        render();
    } else if (e.data.type === 'resize') {
        resize(e.data.width, e.data.height);
    } else if (e.data.type === 'mousemove') {
        mouse.x = e.data.x; mouse.y = e.data.y;
    }
};

function resize(width, height) {
    w = width; h = height;
    if (canvas) { canvas.width = w; canvas.height = h; }
    clouds = [];
    for (let i = 0; i < CONFIG.cloudCount; i++) {
        clouds.push({
            x: Math.random() * w,
            y: Math.random() * h,
            r: Math.random() * (w * 0.8) + (w * 0.4),
            vx: (Math.random() - 0.5) * 1.5,
            vy: (Math.random() - 0.5) * 1.5,
            color: CONFIG.baseColors[i % CONFIG.baseColors.length]
        });
    }
}

function render() {
    if (!ctx) return;
    ctx.clearRect(0, 0, w, h);
    ctx.globalCompositeOperation = 'screen';

    for (let c of clouds) {
        // Mouse Interaction: Gravity
        let dx = mouse.x - c.x;
        let dy = mouse.y - c.y;
        let dist = Math.hypot(dx, dy);

        if (dist < 1000) {
            c.vx += (dx / dist) * CONFIG.mouseGravity;
            c.vy += (dy / dist) * CONFIG.mouseGravity;
        }

        c.x += c.vx;
        c.y += c.vy;
        c.vx *= 0.99; // Damping
        c.vy *= 0.99;

        // Screen Wrap with large padding for clouds
        if (c.x < -c.r) c.x = w + c.r;
        if (c.x > w + c.r) c.x = -c.r;
        if (c.y < -c.r) c.y = h + c.r;
        if (c.y > h + c.r) c.y = -c.r;

        let grad = ctx.createRadialGradient(c.x, c.y, 0, c.x, c.y, c.r);
        grad.addColorStop(0, c.color);
        grad.addColorStop(0.5, c.color.replace('0.1', '0.05'));
        grad.addColorStop(1, 'rgba(0,0,0,0)');

        ctx.fillStyle = grad;
        ctx.beginPath();
        ctx.arc(c.x, c.y, c.r, 0, Math.PI * 2);
        ctx.fill();
    }

    requestAnimationFrame(render);
}

